import{_ as a,C as d,o as r,c as o,E as n,a3 as s}from"./chunks/framework.Bl0ia6y7.js";const i="/S32-User-Manual/versions/v0.9.0/screens/devices/looper.png",y=JSON.parse('{"title":"Looper","description":"","frontmatter":{"title":"Looper","pageClass":"device-doc"},"headers":[],"relativePath":"devices/looper.md","filePath":"devices/looper.md"}'),l={name:"devices/looper.md"};function h(c,t,p,g,b,u){const e=d("DeviceHeading");return r(),o("div",null,[n(e,{slug:"looper",title:"Looper"}),t[0]||(t[0]=s('<p>Loop and overdub MIDI</p><p><img src="'+i+'" alt="Looper parameters" class="screen"></p><h2 id="when-to-use-it" tabindex="-1">When to use it <a class="header-anchor" href="#when-to-use-it" aria-label="Permalink to &quot;When to use it&quot;">​</a></h2><p>Use <strong>Looper</strong> to <strong>record, overdub, and replay</strong> a MIDI phrase inside the rack.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Needs clock for synced loop length and quantize.</p></div><h2 id="parameters" tabindex="-1">Parameters <a class="header-anchor" href="#parameters" aria-label="Permalink to &quot;Parameters&quot;">​</a></h2><div class="device-params-table"><table tabindex="0"><thead><tr><th>Parameter</th><th>Range</th><th>What it does</th></tr></thead><tbody><tr><td>Bypass</td><td>0 – 1</td><td>When on, the device is disabled and MIDI passes through unchanged.</td></tr><tr><td>Record</td><td>0 – 1</td><td>Toggles recording/playback (Looper shows Recording vs Idle).</td></tr><tr><td>Reset</td><td>0 – 1</td><td>Clears the loop buffer (momentary action).</td></tr><tr><td>Mode</td><td>0 – 2</td><td>Looper state: stop, record, or overdub.</td></tr><tr><td>Quantize</td><td>0 – 8</td><td>Grid used when recording loop start/end to clock.</td></tr><tr><td>Length</td><td>1 – 16</td><td>Loop size in bars (1–16) when sync is enabled.</td></tr><tr><td>Countdown</td><td>1 – 4</td><td>Count-in length before recording starts (1–4 bars).</td></tr></tbody></table></div><h2 id="parameter-values" tabindex="-1">Parameter values <a class="header-anchor" href="#parameter-values" aria-label="Permalink to &quot;Parameter values&quot;">​</a></h2><h3 id="bypass" tabindex="-1">Bypass <a class="header-anchor" href="#bypass" aria-label="Permalink to &quot;Bypass&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:right;">Value</th><th>Name</th><th>Meaning</th></tr></thead><tbody><tr><td style="text-align:right;">0</td><td>Off</td><td>Device is active and processes MIDI.</td></tr><tr><td style="text-align:right;">1</td><td>On</td><td>Device is bypassed; messages pass through unchanged.</td></tr></tbody></table><h3 id="mode" tabindex="-1">Mode <a class="header-anchor" href="#mode" aria-label="Permalink to &quot;Mode&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:right;">Value</th><th>Name</th><th>Meaning</th></tr></thead><tbody><tr><td style="text-align:right;">0</td><td>Auto</td><td>M2CV: map notes to CV automatically by pitch.</td></tr><tr><td style="text-align:right;">1</td><td>Channel</td><td>M2CV: one CV channel per MIDI channel.</td></tr><tr><td style="text-align:right;">2</td><td>Gate</td><td>M2CV: emit gate/trigger voltages from note on/off.</td></tr></tbody></table><h3 id="quantize" tabindex="-1">Quantize <a class="header-anchor" href="#quantize" aria-label="Permalink to &quot;Quantize&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:right;">Value</th><th>Name</th><th>Meaning</th></tr></thead><tbody><tr><td style="text-align:right;">0</td><td>Down</td><td>Snap to the nearest scale degree below the input pitch.</td></tr><tr><td style="text-align:right;">1</td><td>Up</td><td>Snap to the nearest scale degree above the input pitch.</td></tr><tr><td style="text-align:right;">2</td><td>Filter</td><td>Drop notes that are not in the scale.</td></tr></tbody></table><h3 id="countdown" tabindex="-1">Countdown <a class="header-anchor" href="#countdown" aria-label="Permalink to &quot;Countdown&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:right;">Value</th><th>Name</th><th>Meaning</th></tr></thead><tbody><tr><td style="text-align:right;">1</td><td>1 bar</td><td>One bar count-in before record.</td></tr><tr><td style="text-align:right;">2</td><td>2 bars</td><td>Two bar count-in.</td></tr><tr><td style="text-align:right;">3</td><td>3 bars</td><td>Three bar count-in.</td></tr><tr><td style="text-align:right;">4</td><td>4 bars</td><td>Four bar count-in.</td></tr></tbody></table>',16))])}const v=a(l,[["render",h]]);export{y as __pageData,v as default};
